+    Capture {
+        /// Output directory for fixture JSON files.
+        #[arg(long)]
+        output: PathBuf,
+        /// Function family to capture (e.g., "string", "malloc").
+        #[arg(long)]
+        family: String,
+    },
+    /// Verify our implementation against captured fixtures.
+    Verify {
