+
+    #[test]
+    fn test_contention_signal() {
+        let signal = ContentionSignal::new();
+        signal.free_begin();
+        signal.free_begin();
+        assert_eq!(signal.concurrent_frees.load(Ordering::Relaxed), 2);
+        signal.free_end();
+        assert_eq!(signal.concurrent_frees.load(Ordering::Relaxed), 1);
