+        if is_transition {
+            self.transition_streak += 1;
+            if self.transition_streak >= CONFIRM_STREAK {
+                if self.phase != PhaseState::NewRegime {
+                    self.transition_count += 1;
+                }
+                self.phase = PhaseState::NewRegime;
