+        // Sum of 0..10 = 45, mean = 4.5
+        let expected_mean = 45.0 / 10.0;
+        let actual_mean = monitor.sums[0] / monitor.count as f64;
+        assert!(
+            (actual_mean - expected_mean).abs() < 1e-10,
+            "mean should be {expected_mean}, got {actual_mean}"
+        );
+    }
